example_bad:
fn main() {
    let mut v = vec![1, 2, 3];
    match v.as_slice() {
        [first, ..] if { v.push(4); true } => { // Error
            println!("{}", first);
        }
        _ => {}
    }
}

fixes.code:
let mut v = vec![1, 2, 3];
let should_extend = true;
if should_extend {
    v.push(4);
}
match v.as_slice() {
    [first, ..] => println!("{}", first),
    _ => {}
}

let v = vec![1, 2, 3];
match v.as_slice() {
    [first, ..] if v.len() > 2 => { // len() is &self, OK
        println!("{}", first);
    }
    _ => {}
}
